Here’s the real program in readable form:

```js
const config = {
  maxParticles: 4000,
  attractionCoeff: 0.004,
  damping: 0.92,
  central: 0.0003,
  streamRate: 40,
  zoomDecay: 0.04,
  smooth: 0.06
};

const nodes = [
  { id: 'hub',     label: 'hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'alpha', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'beta',  b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const camera = { x: 400, y: 300, zoom: 1 };
const cameraTarget = { x: 400, y: 300, zoom: 1 };
const particles = [];
let frame = 0;

function getNode(id) {
  return nodes.find(n => n.id === id) || null;
}

function updateNodePhysics() {
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const d = Math.sqrt(dx*dx + dy*dy) || 1;
      const f = config.central / (d*d);

      nodes[i].vx += (dx / d) * f;
      nodes[i].vy += (dy / d) * f;
      nodes[j].vx -= (dx / d) * f;
      nodes[j].vy -= (dy / d) * f;
    }
  }

  for (const link of links) {
    const a = getNode(link.a);
    const b = getNode(link.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const d = Math.sqrt(dx*dx + dy*dy) || 1;
    const stretch = d - link.rest;
    const f = (link.k || config.attractionCoeff) * stretch;

    a.vx += (dx / d) * f;
    a.vy += (dy / d) * f;
    b.vx -= (dx / d) * f;
    b.vy -= (dy / d) * f;
  }

  for (const n of nodes) {
    n.vx += (400 - n.x) * config.central;
    n.vy += (300 - n.y) * config.central;
    n.vx *= config.damping;
    n.vy *= config.damping;
    n.x += n.vx;
    n.y += n.vy;
  }
}

function spawnParticle() {
  if (particles.length >= config.streamRate) return;

  const src = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * 0.283;
  const speed = 0.3 + Math.random() * 0.707;

  particles.push({
    x: src.x,
    y: src.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 120 + Math.floor(Math.random() * 80),
    size: 0.8 + Math.random() * 0.618 * 0.707
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 1 - config.zoomDecay * 0.125;
    p.vy *= 1 - config.zoomDecay * 0.125;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.smooth;
  camera.y += (cameraTarget.y - camera.y) * config.smooth;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.smooth;
}

function tick() {
  updateNodePhysics();
  updateCamera();
  if (frame % 10 === 0) spawnParticle();
  updateParticles();
  frame++;
}

setInterval(tick, /* small frame interval */);
```

